// n8n Code node — "Build Prompt"
// Placed AFTER the "Fetch Prompt" HTTP Request node
// Combines the system prompt (from GitHub) with order data (from Transform node)

// ─────────────────────────────────────────────────────────────
// 1. Get system prompt from the HTTP Request node output
// ─────────────────────────────────────────────────────────────

const systemPrompt = $('Fetch Script Prompt').first().json.data;

// ─────────────────────────────────────────────────────────────
// 2. Get order from the Transform node
// ─────────────────────────────────────────────────────────────

const order = $('Validate and Transform Order').first().json.order;
const child = order.child;

// ─────────────────────────────────────────────────────────────
// 3. Build user prompt from order data
// ─────────────────────────────────────────────────────────────

const userPrompt = `Create a personalized story with these details:

**Child:**
- Name: ${child.name}
- Age: ${child.age}
- Gender: ${child.gender}
- Glasses: ${child.glasses ? 'yes' : 'no'}
- Hair color: ${child.hair_color}
- Skin tone: ${child.skin_tone}

**Personality & Interests:**
- Hobby: ${child.hobby}
- Hobby details: ${child.hobby_detail || 'not provided'}
- Signature look: ${child.signature_look || 'not provided'}
- Jersey / lucky number: ${child.jersey_number || 'not provided'}
- Recent achievement: ${child.recent_win || 'not provided'}

**Story Settings:**
- Theme: ${order.theme}
- Hero trait: ${child.hero_trait}
- Language: ${order.language}

**Parent's message (include in final scene):**
${order.parent_message || 'No message provided.'}`;

// ─────────────────────────────────────────────────────────────
// 4. Output — ready for OpenAI node
// ─────────────────────────────────────────────────────────────

return [{
    json: {
        system_prompt: systemPrompt,
        user_prompt: userPrompt,
        order_id: order.order_id,
        order: order
    }
}];

// Extract the story JSON string from OpenAI response
const aiOutput = $input.first().json;

// Try multiple paths — n8n OpenAI node output varies by version
let rawText;

if (aiOutput.output?.[0]?.content?.[0]?.text) {
  // Responses API format
  rawText = aiOutput.output[0].content[0].text;
} else if (aiOutput.message?.content) {
  // Chat Completion format
  rawText = aiOutput.message.content;
} else if (aiOutput.text) {
  // Simple text output
  rawText = aiOutput.text;
} else if (typeof aiOutput === 'string') {
  rawText = aiOutput;
} else {
  // Debug: output what we actually received
  throw new Error('Unexpected AI output shape: ' + JSON.stringify(Object.keys(aiOutput)));
}

const cleaned = rawText
	.trim()
	.replace(/^```json\s*/i, '')
	.replace(/^```\s*/i, '')
	.replace(/\s*```$/, '')
	.trim();

// Parse the JSON string into an actual object
const script = JSON.parse(cleaned);

// Get the order from the earlier node
const order = $('Validate and Transform Order').first().json.order;

return [{
  json: {
    order_id: order.order_id,
    script: script,
    script_raw: rawText,
    version: 1,
    order: order
  }
}];

// n8n Code node — "Build Emails"
// Place AFTER: "Fetch Confirmation Email Template", "Fetch Admin Email Template", "Parse Script"
// Outputs TWO items: [0] = customer email, [1] = admin email
// Then use a Send Email node for each (or split with IF)

const order = $('Validate and Transform Order').first().json.order;
const script = $('Parse Script').first().json.script;
const scriptVersion = $('Parse Script').first().json.version || 1;

// ─────────────────────────────────────────────────────────────
// Env flags
// ─────────────────────────────────────────────────────────────
const env = $('Envs').first().json.env;
const approvalRequired = env.script_approval_required === true || env.script_approval_required === 'true';
const REVIEW_BASE = `https://evermagic.app.n8n.cloud/webhook${env.is_live ? '' : '-test'}/evermagic/review`;

// ─────────────────────────────────────────────────────────────
// 1. Customer Confirmation Email
// ─────────────────────────────────────────────────────────────

const packageLabels = {
  'BASIC': 'Basic (Storybook + Coloring + Certificate)',
  'FULL': 'Full Bundle (Video + PDF + printable)',
  'PARTY': 'Party Pack',
};

const themeLabels = {
  'SPACE_HERO':          'Space Hero Mission',
  'FANTASY_HERO':        'Fantasy Hero Quest',
  'ENCHANTED_PRINCESS':  'Enchanted Princess Adventure',
  'ANIMAL_GUARDIAN':     'Animal Guardian Hero',
  'HOME_HELPER':         'Home Helper Hero',
};

// Shared assets
const branch  = env.is_live ? 'main' : 'develop';
const logoUrl = `https://raw.githubusercontent.com/TarasGolub/evermagic/${branch}/templates/icons/logo_email.png`;

// Inject variables into the fetched confirmation email template
const confirmationTemplate = $('Fetch Confirmation Email Template').first().json.data;

const customerHtml = confirmationTemplate
  .replace(/\{\{logo_url\}\}/g,    logoUrl)
  .replace(/\{\{child_name\}\}/g,  order.child.name)
  .replace(/\{\{order_id\}\}/g,    order.order_id)
  .replace(/\{\{child_age\}\}/g,   String(order.child.age))
  .replace(/\{\{package\}\}/g,     packageLabels[order.package] || order.package)
  .replace(/\{\{theme\}\}/g,       themeLabels[order.theme] || order.theme);

// ─────────────────────────────────────────────────────────────
// 2. Admin Review Email
// ─────────────────────────────────────────────────────────────

const scenesHtml = script.scenes.map(s => `
  <tr><td style="padding:8px 32px;">
    <table role="presentation" width="100%" cellpadding="0" cellspacing="0" style="background:#f9fafb;border-radius:8px;border:1px solid #e5e7eb;margin-bottom:8px;">
      <tr><td style="padding:16px;">
        <div style="font-size:11px;text-transform:uppercase;letter-spacing:1px;color:#6b7280;font-weight:600;">Scene ${s.scene_number} · ${s.emotion || ''}</div>
        <h3 style="margin:4px 0 8px;font-size:16px;color:#111;">${s.scene_title}</h3>
        <p style="margin:0 0 12px;font-size:14px;color:#374151;line-height:1.6;">${s.narration}</p>
        <div style="font-size:12px;color:#9ca3af;line-height:1.5;border-top:1px solid #e5e7eb;padding-top:8px;">
          <strong style="color:#6b7280;">🎬 Visual:</strong> ${s.visual_description}
        </div>
      </td></tr>
    </table>
  </td></tr>`).join('\n');

// Build dynamic blocks for admin email
const reviewStatusLabel = approvalRequired ? 'Script Ready for Review' : 'Script Auto-Approved';

const reviewBadgeHtml = approvalRequired
  ? `<span style="display:inline-block;padding:6px 14px;background:#fef3c7;color:#92400e;font-size:12px;font-weight:600;border-radius:20px;text-transform:uppercase;letter-spacing:0.5px;">Needs Review</span>`
  : `<span style="display:inline-block;padding:6px 14px;background:#d1fae5;color:#065f46;font-size:12px;font-weight:600;border-radius:20px;text-transform:uppercase;letter-spacing:0.5px;">Auto-Approved ✅</span>`;

const approveUrl = `${REVIEW_BASE}?order_id=${order.order_id}&version=${scriptVersion}&action=approve`;
const retryUrl   = `${REVIEW_BASE}?order_id=${order.order_id}&version=${scriptVersion}&action=retry`;
const editUrl    = `${REVIEW_BASE}?order_id=${order.order_id}&version=${scriptVersion}&action=edit`;

const actionButtonsHtml = approvalRequired ? `
  <tr><td style="padding:16px 32px 24px;">
    <table role="presentation" width="100%" cellpadding="0" cellspacing="0">
      <tr>
        <td align="center" width="33%" style="padding:0 4px;">
          <a href="${approveUrl}" style="display:block;padding:14px 8px;background:#16a34a;color:#ffffff;font-size:14px;font-weight:700;text-decoration:none;border-radius:8px;text-align:center;">✅ Approve</a>
        </td>
        <td align="center" width="33%" style="padding:0 4px;">
          <a href="${retryUrl}" style="display:block;padding:14px 8px;background:#f59e0b;color:#ffffff;font-size:14px;font-weight:700;text-decoration:none;border-radius:8px;text-align:center;">🔄 Edit &amp; Retry</a>
        </td>
        <td align="center" width="33%" style="padding:0 4px;">
          <a href="${editUrl}" style="display:block;padding:14px 8px;background:#3b82f6;color:#ffffff;font-size:14px;font-weight:700;text-decoration:none;border-radius:8px;text-align:center;">✏️ Manual Edit</a>
        </td>
      </tr>
    </table>
  </td></tr>
  <tr><td style="padding:12px 32px 28px;border-top:1px solid #eee;">
    <p style="margin:0;font-size:12px;color:#9ca3af;text-align:center;">Click an action above to approve, retry with AI, or manually edit this script.</p>
  </td></tr>` : `
  <tr><td style="padding:16px 32px 24px;">
    <table role="presentation" width="100%" cellpadding="0" cellspacing="0" style="background:#f0fdf4;border-radius:8px;border:1px solid #bbf7d0;">
      <tr><td style="padding:16px;text-align:center;">
        <div style="font-size:28px;margin-bottom:8px;">🤖</div>
        <div style="font-size:14px;font-weight:700;color:#065f46;margin-bottom:4px;">Script was auto-approved</div>
        <div style="font-size:13px;color:#6b7280;">Image generation has already started. No action needed.</div>
      </td></tr>
    </table>
  </td></tr>
  <tr><td style="padding:12px 32px 28px;border-top:1px solid #eee;">
    <p style="margin:0;font-size:12px;color:#9ca3af;text-align:center;">This is an FYI notification. Script approval is currently disabled.</p>
  </td></tr>`;

// Inject variables into the fetched admin email template
const adminTemplate = $('Fetch Admin Email Template').first().json.data;

const adminHtml = adminTemplate
  .replace(/\{\{order_id\}\}/g,             order.order_id)
  .replace(/\{\{customer_email\}\}/g,       order.delivery.email)
  .replace(/\{\{package\}\}/g,              packageLabels[order.package] || order.package)
  .replace(/\{\{child_name\}\}/g,           order.child.name)
  .replace(/\{\{child_age\}\}/g,            String(order.child.age))
  .replace(/\{\{theme\}\}/g,                themeLabels[order.theme] || order.theme)
  .replace(/\{\{language\}\}/g,             order.language)
  .replace(/\{\{story_title\}\}/g,          script.title)
  .replace(/\{\{story_tagline\}\}/g,        script.tagline)
  .replace(/\{\{script_version\}\}/g,       String(scriptVersion))
  .replace(/\{\{review_status_label\}\}/g,  reviewStatusLabel)
  .replace(/\{\{review_badge_html\}\}/g,    reviewBadgeHtml)
  .replace(/\{\{action_buttons_html\}\}/g,  actionButtonsHtml)
  .replace(/\{\{scenes_html\}\}/g,          scenesHtml)
  .replace(/\{\{parent_message\}\}/g,       order.parent_message || 'No message provided.');

// ─────────────────────────────────────────────────────────────
// 3. Output both emails as two items
// ─────────────────────────────────────────────────────────────

return [
  {
    json: {
      email_type: 'customer_confirmation',
      to: order.delivery.email,
      subject: `✨ Your magic is being created, ${order.child.name}!`,
      html: customerHtml,
      order_id: order.order_id
    }
  },
  {
    json: {
      email_type: 'admin_review',
      to: 'taras.evermagic@gmail.com',
      subject: `📋 Script Review — ${order.order_id} — ${order.child.name}`,
      html: adminHtml,
      order_id: order.order_id
    }
  }
];

const raw = {};
for (const item of $input.all()) {
  raw[item.json.key] = item.json.value;
}

const env = {
  mode: raw.mode,       
  is_live: raw.mode === 'live',
  script_approval_required: raw.script_approval_required === 'true', 
  evrm_token: raw.evrm_token
};

return [{ json: { env } }];

// ─────────────────────────────────────────────────────────────
// EverMagic — n8n Code Node: "Parse Token"
// Step 3.5 — Intake Token System
//
// Placement: FIRST node after "Receive Order" webhook
//
// Purpose:
//   Extracts token / source / orderNo from hidden Tally fields.
//   Handles the cheat token (EVRM-DEV) immediately.
//   Passes a structured object downstream for the IF + Supabase nodes.
//
// Tally form setup required:
//   Add 3 hidden fields to the Tally form:
//     label: "token"   → pre-filled from URL param ?token=
//     label: "source"  → pre-filled from URL param ?source=
//     label: "orderNo" → pre-filled from URL param ?orderNo=
//
// Output object:
//   {
//     token:           string | null,
//     source:          string,         // 'etsy' | 'unknown' | etc.
//     orderNo:         string | null,  // external order reference
//     skipTokenCheck:  boolean,        // true only for EVRM-DEV cheat token
//     rejectReason:    string | null,  // 'missing_token' if no token at all
//   }
// ─────────────────────────────────────────────────────────────

// ─── Config ────────────────────────────────────────────────────
const CHEAT_TOKEN = 'EVRM-DEV';

// ─── Helpers ───────────────────────────────────────────────────
const body   = $('Receive Order').first().json.body || {};
const data   = body.data || {};
const fields = Array.isArray(data.fields) ? data.fields : [];

function getHiddenField(label) {
  const f = fields.find(f => f?.label === label);
  if (!f) return null;
  const v = f.value;
  if (v === null || v === undefined) return null;
  return String(v).trim() || null;
}

// ─── Extract URL-param hidden fields ───────────────────────────
const token   = getHiddenField('token');
const source  = getHiddenField('source')  || 'unknown';
const orderNo = getHiddenField('orderNo') || null;

// ─── Cheat token — bypass DB check entirely ─────────────────────
if (token === CHEAT_TOKEN) {
  return [{
    json: {
      token,
      source,
      orderNo,
      skipTokenCheck: true,
      rejectReason:   null,
    }
  }];
}

// ─── No token at all — reject immediately ───────────────────────
if (!token) {
  return [{
    json: {
      token:          null,
      source,
      orderNo,
      skipTokenCheck: false,
      rejectReason:   'missing_token',
    }
  }];
}

// ─── Valid-looking token — let Supabase + Validate nodes decide ─
return [{
  json: {
    token,
    source,
    orderNo,
    skipTokenCheck: false,
    rejectReason:   null,
  }
}];

// ─────────────────────────────────────────────────────────────
// EverMagic — n8n Code Node: "Validate Token"
// Step 3.5 — Intake Token System
//
// Placement: AFTER Supabase "Fetch Token from DB" node
//
// Input:
//   $input.first().json      = Supabase row from intake_tokens (or empty if not found)
//   $('Parse Token').first() = { token, source, orderNo, skipTokenCheck }
//
// Output (TRUE branch = IF node passes through):
//   { tokenValid: true,  token, source, orderNo }
//
// Output (FALSE branch = reject path):
//   { tokenValid: false, rejectReason: 'already_used' | 'not_found' }
//
// Supabase node setup (before this):
//   Operation: getAll
//   Table: intake_tokens
//   Filter: token eq {{ $('Parse Token').first().json.token }}
//   Limit: 1
// ─────────────────────────────────────────────────────────────

const tokenRow  = $input.first().json;          // Supabase row — may be empty object {}
const parsed    = $('Parse Token').first().json; // { token, source, orderNo }

const rowExists = tokenRow && tokenRow.token;   // real row has a token column
const isUnused  = rowExists && tokenRow.status === 'unused';

if (!rowExists) {
  // Token not found in DB at all
  return [{
    json: {
      tokenValid:   false,
      rejectReason: 'not_found',
      token:        parsed.token,
      source:       parsed.source,
      orderNo:      parsed.orderNo,
    }
  }];
}

if (!isUnused) {
  // Token exists but has already been used
  return [{
    json: {
      tokenValid:   false,
      rejectReason: 'already_used',
      token:        parsed.token,
      source:       parsed.source,
      orderNo:      parsed.orderNo,
    }
  }];
}

// ✅ Token is valid and unused
return [{
  json: {
    tokenValid:   true,
    rejectReason: null,
    token:        tokenRow.token,
    source:       parsed.source,
    orderNo:      parsed.orderNo,
  }
}];

// ─────────────────────────────────────────────────────────────
// EverMagic — n8n Code Node: "Reject Token"
// Step 3.5 — Intake Token System
//
// Placement: FALSE branch of "If Token Valid" IF node
//            Connect output to a "Respond to Webhook" node
//
// Purpose: Builds a reject payload for the Respond to Webhook node.
//
// After this node, add a "Respond to Webhook" node:
//   Respond With: JSON
//   Response Code: 400
//   Response Body: {{ $json.errorBody }}
// ─────────────────────────────────────────────────────────────

const parsed      = $('Parse Token').first().json;
const rejectReason = parsed.rejectReason
                  || $('Validate Token').first().json.rejectReason
                  || 'invalid_token';

const messages = {
  missing_token: 'This form requires a valid access token. Please use the link you received in your order email.',
  not_found:     'This access token is not recognised. Please check your order email and use the link provided.',
  already_used:  'This access link has already been used. Each link can only be used once. Please contact support if you need help.',
};

const message = messages[rejectReason] || 'This access link is not valid. Please contact support.';

return [{
  json: {
    errorBody: JSON.stringify({
      error:   rejectReason,
      message: message,
    })
  }
}];

// n8n Function node — Tally webhook → EverMagic order order JSON
// Input: items[0].json = n8n Webhook payload (as in your sample)
// Output: items[0].json.order + items[0].json.validation_errors (if any)

const input = $('Receive Order').first().json;

// ─────────────────────────────────────────────────────────────
// Locate Tally body + fields safely
// ─────────────────────────────────────────────────────────────
const body = input.body || {};
const data = body.data || {};
const fields = Array.isArray(data.fields) ? data.fields : [];
const getField = (label) => fields.find(f => f?.label === label) || null;

function getValue(label) {
  const field = getField(label);
  return field ? field.value : null;
};
function asString(v) {
  if (v === null || v === undefined) return null;
  if (typeof v === 'string') return v.trim();
  return String(v).trim();
};

const customerEmail = asString(getValue('email'));
const token = $('Parse Token').first().json.token;

const env     = $('Envs').first().json.env;
const branch  = env.is_live ? 'main' : 'develop';
const logoUrl = `https://raw.githubusercontent.com/TarasGolub/evermagic/${branch}/templates/icons/logo_email.png`;

const template = $input.first().json.data;

const html = template
  .replace(/\{\{logo_url\}\}/g,   logoUrl)
  .replace(/\{\{order_ref\}\}/g,  token);

return [{
  json: {
    to:      customerEmail,
    subject: `Something went wrong with your EverMagic order - ${token}`,
    html:    html,
  }
}];

// n8n Function node — Tally webhook → EverMagic order order JSON
// Input: items[0].json = n8n Webhook payload (as in your sample)
// Output: items[0].json.order + items[0].json.validation_errors (if any)

const input = $('Receive Order').first().json;

// ─────────────────────────────────────────────────────────────
// Locate Tally body + fields safely
// ─────────────────────────────────────────────────────────────
const body = input.body || {};
const data = body.data || {};
const fields = Array.isArray(data.fields) ? data.fields : [];

// ─────────────────────────────────────────────────────────────
// Helpers
// ─────────────────────────────────────────────────────────────

const getField = (label) => fields.find(f => f?.label === label) || null;

// Dropdown / Radio in Tally: value: [optionId], options: [{id,text}]
function getDropdownText(label) {
  const field = getField(label);
  if (!field) return null;

  const selectedId = Array.isArray(field.value) ? field.value[0] : null;
  if (!selectedId) return null;

  const opt = Array.isArray(field.options) ? field.options.find(o => o.id === selectedId) : null;
  return opt?.text ?? null;
}

// Checkbox group (like glasses): Tally sends extra boolean fields with labels "glasses (Yes)" etc.
function getYesNoCheckbox(labelBase) {
  const hit = fields.find(f =>
    typeof f?.label === 'string' &&
    f.label.startsWith(`${labelBase} (`) &&
    f.value === true
  );
  if (!hit) return null;

  const m = hit.label.match(/\((.+)\)$/);
  return (m && m[1]) ? m[1].trim() : true;
}

function getValue(label) {
  const field = getField(label);
  return field ? field.value : null;
}

function asString(v) {
  if (v === null || v === undefined) return null;
  if (typeof v === 'string') return v.trim();
  return String(v).trim();
}

function asInt(v) {
  if (v === null || v === undefined || v === '') return null;
  const n = Number(v);
  return Number.isFinite(n) ? Math.trunc(n) : null;
}

function normalizePackage(text) {
  const t = (text || '').toLowerCase();
  if (t.includes('basic')) return 'BASIC';
  if (t.includes('full')) return 'FULL';
  if (t.includes('party')) return 'PARTY';
  return text ? text.toUpperCase().replace(/\s+/g, '_') : null;
}

function normalizeLanguage(text) {
  const t = (text || '').toUpperCase();
  if (t.includes('(EN') || t.includes('ENGLISH')) return 'EN';
  if (t.includes('(UA') || t.includes('UKRAIN')) return 'UA';
  return 'EN';
}

function normalizeTheme(text) {
  const t = (text || '').toLowerCase();
  if (t.includes('space'))     return 'SPACE_HERO';
  if (t.includes('fantasy'))   return 'FANTASY_HERO';
  if (t.includes('princess'))  return 'ENCHANTED_PRINCESS';
  if (t.includes('animal') || t.includes('guardian')) return 'ANIMAL_GUARDIAN';
  if (t.includes('home') || t.includes('helper'))     return 'HOME_HELPER';
  return text ? text.toUpperCase().replace(/\s+/g, '_') : 'SPACE_HERO';
}

function normalizeTrait(text) {
  const t = (text || '').toLowerCase();
  if (t.includes('brave')) return 'brave';
  if (t.includes('kind')) return 'kind';
  if (t.includes('smart')) return 'smart';
  if (t.includes('creative')) return 'creative';
  return text ? t : null;
}

function getFiles(label) {
  const v = getValue(label);
  if (!v || !Array.isArray(v)) return [];
  return v
    .map(f => ({
      id: f.id || null,
      name: f.name || null,
      url: f.url || null,
      mime: f.mimeType || null,
      size: f.size || null,
    }))
    .filter(x => x.url);
}

function generateOrderId(prefix = 'EM') {
  const now = new Date();
  const y = now.getFullYear();
  const m = String(now.getMonth() + 1).padStart(2, '0');
  const d = String(now.getDate()).padStart(2, '0');
  const rand = Math.random().toString(36).slice(2, 6).toUpperCase();
  return `${prefix}-${y}${m}${d}-${rand}`;
}

// Consent checkbox: your payload includes label "consent ()" with value true
function getConsentAccepted() {
  const direct = fields.find(f =>
    (f?.label === 'consent' && Array.isArray(f.value) && f.value.length > 0)
  );
  if (direct) return true;

  const boolEntry = fields.find(f =>
    typeof f?.label === 'string' &&
    f.label.startsWith('consent') &&
    f.value === true
  );
  return Boolean(boolEntry);
}

// ─────────────────────────────────────────────────────────────
// Extract raw values
// ─────────────────────────────────────────────────────────────

const email = asString(getValue('email'));
const packageText = getDropdownText('package');
const languageText = getDropdownText('language');

const childName = asString(getValue('child_name'));
const age = asInt(getValue('age'));
const genderText = getDropdownText('gender');

const glassesYN = getYesNoCheckbox('glasses'); // returns "Yes" or "No" or null
const glasses = glassesYN ? glassesYN.toLowerCase() === 'yes' : null;

const hairColorText = getDropdownText('hair_color');
const skinToneText = getDropdownText('skin_tone');

const hobby = asString(getValue('hobby'));
const hobbyDetail = asString(getValue('hobby_detail'));
const signatureLook = asString(getValue('signature_look'));
const jerseyNumber = asString(getValue('jersey_number'));
const recentWin = asString(getValue('recent_win'));

const themeText = getDropdownText('theme');
const heroTraitText = getDropdownText('hero_trait');
const parentMessage = asString(getValue('parent_message'));

const photoMain = getFiles('photo_main');
const photoExtra = getFiles('photo_extra');

const consentAccepted = getConsentAccepted();

// ─────────────────────────────────────────────────────────────
// Normalize
// ─────────────────────────────────────────────────────────────

const order = {
  order_id: generateOrderId('EM'),

  package: normalizePackage(packageText),
  language: normalizeLanguage(languageText),
  theme: normalizeTheme(themeText),

  delivery: { email },

  child: {
    name: childName,
    age,
